import boto3
import sys

def create_sns_subscription(topic_arn, endpoint):
    sns = boto3.client('sns')
    try:
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        print(f"Subscription created successfully. SubscriptionArn: {response['SubscriptionArn']}")
        return response['SubscriptionArn']
    except Exception as e:
        print(f"Error creating subscription: {str(e)}")
